fn is_convex_quadrilateral(points: &[&Vec<i64>]) -> bool {
    let n = points.len();
    if n != 4 {
        return false;
    }

    let mut signs = Vec::new();
    for i in 0..n {
        let p0 = points[i];
        let p1 = points[(i + 1) % n];
        let p2 = points[(i + 2) % n];

        let cross = (p1[0] - p0[0]) * (p2[1] - p0[1]) - (p1[1] - p0[1]) * (p2[0] - p0[0]);
        if cross == 0 {
            return false; // Colinear points
        }
        signs.push(cross > 0);
    }

    // All signs should be the same for convexity
    signs.iter().all(|&x| x == signs[0]) || signs.iter().all(|&x| x == !signs[0])
}
