fn solve(points: Vec<Vec<i64>>) -> i64 {
    let n = points.len();
    let mut count = 0;

    for a in 0..n {
        for b in a + 1..n {
            let mut slopes = std::collections::HashMap::new();
            for c in 0..n {
                if c == a || c == b {
                    continue;
                }
                let dx_ab = points[b][0] - points[a][0];
                let dy_ab = points[b][1] - points[a][1];
                let dx_ac = points[c][0] - points[a][0];
                let dy_ac = points[c][1] - points[a][1];

                // Compute cross product to check if points are collinear
                let cross = dx_ab * dy_ac - dy_ab * dx_ac;
                if cross == 0 {
                    continue; // skip collinear points to avoid parallelograms
                }

                // Compute slope as a reduced fraction to avoid floating point inaccuracies
                let (mut num, mut den) = (dy_ab, dx_ab);
                if den == 0 {
                    // vertical line, use None to represent vertical slope
                    slopes.entry(None).or_insert(vec![]).push(c);
                } else {
                    // reduce the fraction
                    let gcd = num.abs().gcd(den.abs());
                    num /= gcd;
                    den /= gcd;
                    if den < 0 {
                        num *= -1;
                        den *= -1;
                    }
                    slopes.entry(Some((num, den))).or_insert(vec![]).push(c);
                }
            }

            // Check for parallel lines (same slope)
            for (slope, indices) in slopes.iter() {
                if indices.len() >= 2 {
                    // There are at least two other points forming a line parallel to AB
                    // The number of ways to choose 2 points from these is C(k, 2)
                    let k = indices.len() as i64;
                    count += k * (k - 1) / 2;
                }
            }
        }
    }

    // Each trapezoid is counted twice (once for each pair of parallel sides)
    count / 2
}
