    let n = points.len();
    let mut count = 0;

    for a in 0..n {
        for b in a + 1..n {
            for c in b + 1..n {
                for d in c + 1..n {
                    let p1 = &points[a];
                    let p2 = &points[b];
                    let p3 = &points[c];
                    let p4 = &points[d];
                    let points = [p1, p2, p3, p4];

                    // Check all possible pairs of parallel sides
                    let mut is_trapezoid = false;

                    // Check all combinations of two pairs of lines
                    // Pair 1: (0,1) and (2,3)
                    let slope1 = slope(points[0], points[1]);
                    let slope2 = slope(points[2], points[3]);
                    if (slope1 == slope2) && !is_parallel_quad(points[0], points[1], points[2], points[3]) {
                        is_trapezoid = true;
                    }

                    // Pair 2: (0,2) and (1,3)
                    let slope1 = slope(points[0], points[2]);
                    let slope2 = slope(points[1], points[3]);
                    if (slope1 == slope2) && !is_parallel_quad(points[0], points[2], points[1], points[3]) {
                        is_trapezoid = true;
                    }

                    // Pair 3: (0,3) and (1,2)
                    let slope1 = slope(points[0], points[3]);
                    let slope2 = slope(points[1], points[2]);
                    if (slope1 == slope2) && !is_parallel_quad(points[0], points[3], points[1], points[2]) {
                        is_trapezoid = true;
                    }

                    if is_trapezoid {
                        count += 1;
                    }
                }
            }
        }
    }

    count
}

fn slope(p1: &Vec<i64>, p2: &Vec<i64>) -> Option<(i64, i64)> {
    let dx = p2[0] - p1[0];
    let dy = p2[1] - p1[1];
    if dx == 0 && dy == 0 {
        None
    } else if dx == 0 {
        Some((1, 0)) // vertical line, represented as (1, 0) to avoid division
    } else if dy == 0 {
        Some((0, 1)) // horizontal line, represented as (0, 1)
    } else {
        let g = gcd(dx, dy);
        Some((dx / g, dy / g))
    }
}

fn gcd(a: i64, b: i64) -> i64 {
    if b == 0 { a.abs() } else { gcd(b, a % b) }
}

fn is_parallel_quad(p1: &Vec<i64>, p2: &Vec<i64>, p3: &Vec<i64>, p4: &Vec<i64>) -> bool {
    // Check if the four points form a parallelogram (both pairs of sides are parallel)
    let slope1 = slope(p1, p2);
    let slope2 = slope(p3, p4);
    let slope3 = slope(p1, p3);
    let slope4 = slope(p2, p4);

    slope1 == slope2 && slope3 == slope4
}
