fn is_trapezoid(points: &[&Vec<i64>; 4]) -> bool {
    let mut slopes = Vec::new();
    for i in 0..4 {
        for j in i + 1..4 {
            let (x1, y1) = (points[i][0], points[i][1]);
            let (x2, y2) = (points[j][0], points[j][1]);
            if x1 == x2 {
                slopes.push((i, j, std::i64::MAX));
            } else {
                let slope = (y2 - y1) as f64 / (x2 - x1) as f64;
                slopes.push((i, j, slope.to_bits()));
            }
        }
    }

    for i in 0..slopes.len() {
        for j in i + 1..slopes.len() {
            let (a1, b1, s1) = slopes[i];
            let (a2, b2, s2) = slopes[j];
            if s1 == s2 {
                let mut indices = vec![a1, b1, a2, b2];
                indices.sort();
                indices.dedup();
                if indices.len() == 4 {
                    return true;
                }
            }
        }
    }

    false
}
